INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (1, 'スーパーマリオブラザーズ', 'スーパーマリオブラザーズ', '「スーパーマリオブラザーズ」は、1985年に任天堂から発売されたファミリーコンピュータ用の横スクロール型アクションゲームで、プレイ人数は1-2名。シリーズ化され、多くの続編や追随するゲームを生みました。敵に触れるとダメージを受ける従来のアクションゲームのフォーマットを突き崩し、踏むことが敵に対する攻撃方法として確立されたことで世界的なヒットとなりました。キャッチコピーは「奇想天外。夢の大冒険ゲーム！」「地上に地下に海に空に謎のキャラクタ出現！」。\r\nストーリーは、クッパ率いるカメ一族によってキノコ王国のお姫様ピーチがさらわれ、配管工の兄弟マリオとルイージがピーチを助けるため、クッパが率いる敵たちを倒していざクッパがいる城へ向かうというものです。\r\nプレイヤーは敵や障害物を避けながら、制限時間内にゴールの旗へたどり着くことが目的で、2人でプレイする場合はマリオが1プレイヤーキャラクター、ルイージが2プレイヤーキャラクターとなります。\r\nゲームは社会現象となり、ファミコンゲームや家庭用ゲームの認知度を高めるのに貢献したとされています。\r\n発売20周年を迎えた2005年以降、5年毎に大規模なアニバーサリーイベントが行われており、2020年には「ゲーム&ウオッチスーパーマリオブラザーズ」が販売されました。', 'FC-001', 1, 1, 1, '', '奇想天外。夢の大冒険ゲーム!', '', 4900, '1985-09-30', 'https://www.nintendo.co.jp/software/smb1/index.html', 'https://www.youtube.com/embed/tJ0vCvYNawg', 1, 1, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (2, 'スーパーマリオブラザーズ2', 'スーパーマリオブラザーズツー', '「スーパーマリオブラザーズ2」は、任天堂から1986年に発売されたアクションゲームです。前作のステージを一新し、新しいシステムを導入しました。難易度が高いとされ、上級者向けの開発とされました。日本国内ではディスクシステム用ソフトとして発売され、その後、日本国外では「スーパーマリオブラザーズ: The Lost Levels」として発売されました。国内外で微妙な差異があるため、日本国外での発表や発売はオムニバスリメイク作品『スーパーマリオコレクション』の日本国外版『Super Mario All-Stars』で収録されるまで待たなければなりませんでした。ゲームの内容は、前作と比べて、敵キャラクターや目的などは大きく変わってはいないが、新しいアイデアが取り入れられています。また、ステージによっては、マリオやルイージを使い分ける必要があります。', 'FCD-001', 1, 2, 1, '横スクロールアクション', 'ムカっと来るけどやめられない', '', 2500, '1986-06-03', 'https://www.nintendo.co.jp/software/smb2/index.html', 'https://www.youtube.com/embed/WZ8goc49oEM', 1, 1, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (3, 'スーパーマリオブラザーズ3', 'スーパーマリオブラザーズスリー', '「スーパーマリオブラザーズ3」は、任天堂が1988年に発売した横スクロールアクションゲームで、同社の「スーパーマリオシリーズ」の第三作目です。プレイヤーは主人公のマリオとルイージを操作し、クッパから魔法の杖を取り戻すことや攫われたピーチ姫を救出することが目的です。本作は前作を踏襲しながら、すごろく状のマップやミニゲームなどの要素が追加され、容量も前作の6倍に拡張されたため、ステージ数が倍増し、多彩なステージ、マリオの変身要素、キャラクターの追加などが行われました。難易度は序盤から比較的易しいが、中盤から後半にかけて難易度が上がり、アクションが苦手なプレイヤー向けの新システムも導入されています。販売本数は国内で約384万本、全世界で約1728万本に達し、「スーパーマリオ3」や「マリオ3」といった略称で親しまれています。本作は、ゲーム誌「ファミコン通信」の「クロスレビュー」にてプラチナ殿堂入りを獲得し、また「ゲーム通信簿」の「ロムカセット部門」においてキャラクター2位、操作性3位、熱中度4位、総合評価3位を獲得しました。', 'FC-002', 1, 1, 1, '横スクロールアクション', '僕らはマリオと強くなる。', '', 6500, '1988-10-23', 'https://www.nintendo.co.jp/character/mario/archives/smb3/index.html', 'https://www.youtube.com/embed/arbzyBswOTs', 1, 1, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (4, 'ドクターマリオ', 'ドクターマリオ', '「ドクターマリオ」は、1990年に任天堂より発売された落ち物パズルゲームであり、主人公のマリオが医師に扮して、ウイルスをビンから取り除くゲームです。ウイルスは3つの色があり、カプセルの色と一致させて4つ以上つなげることで消すことができます。スピードとレベルを調整して自分の実力に合わせた設定でプレイすることができ、BGMは3種類から選ぶことができる。このゲームは、多数のメディアで露出され、主婦層を含め長期にわたって人気を獲得しました。また、後継作品の「ヨッシーのたまご」が発売されるまでの間、このゲームは他社の類似作品と比べても高い人気を誇りました。', 'FC-003', 1, 1, 11, '落ち物パズルゲーム', '新次元体験のアクティブパズル!!', '', 4757, '1990-07-27', 'https://www.nintendo.co.jp/n02/dmg/vua/index.html', 'https://www.youtube.com/embed/KNa52U8nyUE', 1, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (5, 'ドラゴンクエスト', 'ドラゴンクエスト', '『ドラゴンクエスト』は、1986年に発売された日本初のオリジナルタイトルのロールプレイングゲームであり、家庭用ゲーム機でのリリースとしても初めてのものになります。プレイヤーは、伝説の勇者「ロト」の血を引く勇者として、竜王にさらわれた姫を救い出し、そして竜王を倒すことが目的です。敵キャラクターを倒して経験値と通貨となるゴールドを稼ぎ、レベルを上げ強い武器・防具を購入してプレイヤーキャラクターを強くし、探索範囲を徐々に広げていく必要があり、町の人々から情報を得て、それをヒントに重要アイテムを手に入れて謎を解くことも必要です。『ドラゴンクエスト』は、『ドラゴンクエストIII』の発売後には、小説化やゲームブック化に加え、ドラマCD化も行われ、後にリメイク版としてSFC、GB、Wii、スマートフォン、Nintendo Switch、PlayStation 4、ニンテンドー3DS版などが発売されました。また、北米では『Dragon Warrior』として任天堂から発売され、GB版『Dragon Warrior I & II』にも収録されました。', 'FC-004', 10, 1, 3, '', '今、新しい伝説が生まれようとしている', '', 5500, '1986-05-27', 'https://www.jp.square-enix.com/game/detail/dq/', 'https://www.youtube.com/embed/YZBDHZDlxec', 1, 1, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (6, 'ドラゴンクエストII 悪霊の神々', 'ドラゴンクエストツーアクリョウノカミガミ', '「ドラゴンクエストII 悪霊の神々」は、1987年1月26日に株式会社エニックス（現：株式会社スクウェア・エニックス）から発売された、ファミリーコンピュータ用ロールプレイングゲームです。前作から100年後の物語で、勇者ロトの血を引く前作の主人公の子孫3人によって、邪教の教祖によって破られた世界の平和を再び取り戻すことが目的となっています。本作は、発売後すぐに品切れとなり、大ヒットとなったため、「ドラゴンクエスト現象」と称されるようになりました。続編である「ドラゴンクエストIII そして伝説へ…」の発売後、ゲームブック化や小説化、ドラマCD化も行われました。北米では、1990年にNESにて「Dragon Warrior II」として発売され、GB版「Dragon Warrior I & II」にも収録されています。ファミリーコンピュータ版は、ゲーム誌「ファミコン通信」の「クロスレビュー」にてプラチナ殿堂入りを獲得し、「ゲーム通信簿」でも高い評価を受けた。また、本作で取り入れられたシステムの大部分は後の作品にも受け継がれました。', 'FC-005', 10, 1, 3, '', '勇者の伝説が再びよみがえる', '', 5500, '1987-01-26', 'https://www.jp.square-enix.com/game/detail/dq2/', 'https://www.youtube.com/embed/WMT6VWsym7I', 1, 1, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (7, 'ドラゴンクエストIII そして伝説へ…', 'ドラゴンクエストスリーソシテデンセツヘ', '『ドラゴンクエストIII そして伝説へ…』は、1988年にエニックスから発売された、ファミリーコンピュータ用のロールプレイングゲームで、ドラゴンクエストシリーズの第3作目です。鳥山明がキャラクターデザイン、すぎやまこういちが音楽を担当し、堀井雄二が脚本・ゲームデザインを手掛けました。前2作に登場する伝説の勇者「ロト」の物語が本作で完結し、アレフガルドの秘密が明かされます。発売当時は社会現象を巻き起こし、数キロメートルの行列ができたと言われています。リメイク版が1996年にスーパーファミコン、2000年にゲームボーイカラーで発売され、2009年からは携帯アプリ版も配信されました。ファミリーコンピュータ版とスーパーファミコン版はゲーム誌『ファミコン通信』の「クロスレビュー」にてプラチナ殿堂入りを獲得しました。また、リメイク版を含めた合計ではシリーズで最も売れたタイトルです。北米では、『Dragon Warrior III』としてNES版とGBC版が発売されました。', 'FC-006', 10, 1, 3, '', 'さらば、母なるアリアハン', '', 5900, '1988-02-10', 'https://www.jp.square-enix.com/game/detail/dq3/', 'https://www.youtube.com/embed/t186Rjs2MNk', 1, 1, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (8, 'ドラゴンクエストIV 導かれし者たち', 'ドラゴンクエストフォーミチビカレシモノタチ', '『ドラゴンクエストIV 導かれし者たち』は、1990年2月11日にエニックスから発売されたファミリーコンピュータ用のロールプレイングゲームです。『ドラゴンクエスト』シリーズの第4作目で、FC版として発売された最後の作品になります。5つの章に分かれたシナリオ、AIによる戦闘システムや5人以上の仲間キャラクターと同時に冒険できる馬車システムが導入されました。タイトルロゴには城が描かれています。北米では『Dragon Warrior IV』のタイトルで1992年に発売され、2008年には『Dragon Quest IV: Chapters of the Chosen』のタイトルでDS版が再発売されました。本作は、ゲームブック化や小説化、ドラマCD化が行われ、スピンオフ化や世界設定を基にした外伝的な漫画作品も登場しました。リメイク版として、PlayStation版、ニンテンドーDS版、スマートフォン版が発売されています。『ファミコン通信』の「クロスレビュー」にてプラチナ殿堂を獲得した他、「''90ベストヒットゲーム大賞」にて読者支持1位およびRPG賞を受賞しました。また、PS版およびDS版はゴールド殿堂を獲得し、DS版は日本ゲーム大賞2008にて優秀賞を受賞しました。本作は当時としては膨大な4メガビットのROM容量を使用し、『ドラゴンクエスト』シリーズの中でも特に評価が高い作品とされています。', 'FC-007', 10, 1, 3, '', '勇者よ、目覚めなさい', '', 8500, '1990-02-11', 'https://www.jp.square-enix.com/game/detail/dq4/', 'https://www.youtube.com/embed/Cyf9ywhFgUY', 1, 1, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (9, '第2次スーパーロボット大戦', 'ダイニジスーパーロボットタイセン', '『第2次スーパーロボット大戦』は、1991年にバンプレストが日本で発売したファミリーコンピュータ用シミュレーションロールプレイングゲームです。同社のクロスオーバー作品であり、SDで表現されたロボットたちが競演するスーパーロボット大戦シリーズの第2作目になります。前作とストーリーのつながりはなく、シリーズカテゴリの一つである「DC戦争シリーズ」の第1作目にあたります。開発はウィンキーソフトが行い、プロデューサーはじっぱひとからげ、ゲーム・デザインは阪田雅彦が担当した他、音楽は田中伸一が担当しています。本作は、パイロットが初採用され、原作での人間関係が再現され、深みのある物語が展開されるようになりました。ユニットはパイロットのレベルアップに合わせてパワーアップし、武器は1ユニットあたり2つであり、さまざまな組み合わせがあります。また、シナリオの進行によってより強力なユニットが手に入り、さらにパワーアップすることができます。本作は、リメイク版がゲームボーイ用ソフト『第2次スーパーロボット大戦G』（1995年）として、PlayStation用ソフトとしてもリメイク版が1999年に発売されました。', 'FC-008', 11, 1, 4, 'シミュレーションRPG', 'キャラクターによるドラマ性を加えた「シミュラマ」', '', 8200, '1991-12-29', '', 'https://www.youtube.com/embed/TDhLwnA5llA', 1, 0, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (10, '熱血高校ドッジボール部', 'ネッケツコウコウドッジボールブ', '『熱血高校ドッジボール部』は、1988年にテクノスジャパンからファミリーコンピュータ用ゲームソフトとして発売されました。これは、1987年にアーケードゲームとしてリリースされた同名の作品の移植版です。その後、Windows版やバーチャルコンソールなどで配信され、2016年の『くにおくん熱血コンプリート ファミコン編』や2018年の『くにおくん ザ・ワールド〜クラシックスコレクション〜』にも収録されています。また、『くにおくん ザ・ワールド〜クラシックスコレクション〜』には、海外版の『Super Dodge Ball』も含まれています。', 'FC-009', 12, 1, 7, '', '多彩な必殺シュートで見た目にも派手なハチャメチャなスポーツ', '', 5800, '1988-07-26', '', 'https://www.youtube.com/embed/UyjUaGLd8xA', 1, 1, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (11, '熱血高校ドッジボール部 サッカー編', 'ネッケツコウコウドッジボールブサッカーヘン', '「熱血高校ドッジボール部 サッカー編」は、くにおくんシリーズの一作で、1990年にテクノスジャパンからファミリーコンピュータ用ゲームソフトとして発売されました。1分30秒ハーフで6対6のチーム編成で行われる、ファウルが基本的に存在しないケンカサッカーをテーマとします。欧米では『NINTENDO WORLD CUP』として発売され、くにおくんシリーズの設定が世界代表に変更されている。本作品は、EZwebアプリ、バーチャルコンソールなどで配信もされています。', 'FC-010', 12, 1, 7, 'サッカー', 'ルール無用のハチャメチャケンカサッカー', '', 5900, '1990-05-18', '', 'https://www.youtube.com/embed/pvvV0dK5_9M', 1, 1, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (12, 'くにおくんの熱血サッカーリーグ', 'クニオクンノネッケツサッカーリーグ', '「くにおくんの熱血サッカーリーグ」は、1993年にファミリーコンピュータ用に発売されたゲームで、前作「熱血高校ドッジボール部 サッカー編」の続編です。プレイヤーは、くにおやげんえいを含む「熱血高校ドッジボール部 サッカー編」のキャラクターたちと日本代表「熱血FC」を率いて、世界各国のサッカーチームと対戦し、熱血サッカーリーグ世界一を決定する「テクノスジャパン・カップ」で優勝することが目的です。ゲーム内の選手には、体力、シュート力、防御力、走力などのステータスがあり、さらに走力には4つのタイプがあります。プレイヤーは熱血リーグモードで対戦する国を選び、一定数勝利するとトーナメント形式のテクノスジャパンカップに進むことができます。選手の機嫌は、「みーてぃんぐ」やアイテムを使用することで変化し、選手データを見ることで性格や好物を知ることができます。2人までの協力プレイや最大4人の対戦モードもあり、PKモードも遊ぶことができます。', 'FC-011', 12, 1, 7, 'サッカー', 'うふっ♥　がんば～！　熱血ＦＣ！！', '', 6500, '1993-04-23', '', 'https://www.youtube.com/embed/bSkPooqmboA', 1, 0, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (13, 'ダウンタウンスペシャル くにおくんの時代劇だよ全員集合!', 'ダウンタウンスペシャル クニオクンノジダイゲキダヨゼンインシュウゴウ！', '「くにおくんの時代劇だよ全員集合！」は、1991年に発売されたファミリーコンピュータ用アクションロールプレイングゲームで、熱血シリーズのキャラクターが時代劇を演じます。主人公のくに政は、攫われたお琴を救うために戦います。テクノスジャパンが開発し、吉田晄浩がゲーム・デザイン、田崎寿子が音楽、根立克行がキャラクター・デザインを担当。ゲームボーイ版も発売され、iアプリ、Vアプリにて配信されました。また、バーチャルコンソール対応ソフトとして、ファミリーコンピュータ版はWii、ニンテンドー3DS、Wii U、ゲームボーイ版はニンテンドー3DS用として配信されました。', 'FC-012', 12, 1, 1, '', '敵を追いつつ追われつつ日本中を駆ける', '', 6500, '1991-07-26', '', 'https://www.youtube.com/embed/EgGMmg_7n0g', 1, 1, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (14, 'ダウンタウン熱血行進曲 それゆけ大運動会', 'ダウンタウンネッケツコウシンキョクソレユケダイウンドウカイ', '『ダウンタウン熱血行進曲 それゆけ大運動会』は、1990年にテクノスジャパンから発売されたファミリーコンピュータ用対戦アクションゲームソフトです。冷峰学園の新生徒会長「藤堂」の発案により開催された運動会を舞台に、他校の生徒を一掃するために過酷な競技内容となっており、熱血高校チームや花園高校チームなどが参戦し優勝を目指す内容となります。開発はテクノスジャパンが行い、ディレクターは『ダウンタウン熱血物語』を手掛けた関本弘之、音楽は澤和雄が担当しました。また、ゲームボーイ版やPCエンジンSUPER CD-ROM²版などのリメイク版が後に発売されました。ゲームは、クロスカントリーや玉割りなどを行い、得点を競う内容で、最大4人までの同時対戦が可能。競技中の「殴る・蹴る・武器の使用」がルールで認められている点も特徴です。', 'FC-013', 12, 1, 1, '', 'くにおくん達が高校ごとに4つのチームを組み4つの特殊な競技を戦う', '', 6200, '1990-10-12', '', 'https://www.youtube.com/embed/oq_icUGSWqQ', 1, 1, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (15, '熱血格闘伝説', 'ネッケツカクトウデンセツ', '『くにおくんの熱血闘技場』は、くにおを主人公にしない熱血シリーズの一つで、ファミコンのドット絵による対戦格闘ゲームとして開発されました。\r\nプレイヤーは自分のパーソナルデータを入力し、自分を主人公にして熱血世界に入れることができます。ストーリーは他の熱血シリーズのタイトルよりも硬派で、真剣勝負や最強、友情などを前面に押し出しています。『くにおくんの熱血闘技場』は、後にニンテンドー3DSソフト『くにおくん熱血コンプリート ファミコン編』に収録されました。', 'FC-014', 12, 1, 1, '', 'シリーズ初のオリジナル主人公が作れる作品', '', 6500, '1992-12-23', '', 'https://www.youtube.com/embed/9TcOqofwHKc', 1, 1, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (16, 'びっくり熱血新記録! はるかなる金メダル', 'ビックリネッケツシンキロク！ハルカナルキンメダル', '『びっくり熱血新記録』は、1992年にテクノスジャパンより発売されたスポーツゲームです。プレイヤーは熱血高校チームやオクラホマハイスクールなどの5つのチームを選び、400mハードルなど5つの競技でメダル数を競います。競技ごとに操作方法が異なり、1人から最大4人までプレイ可能です。金メダルの数で競い、銀メダルや銅メダルを集めると上位のメダルに変換できます。ノーマルモード、ショートモード、練習モードの3つがあり、WiiやWii U、ニンテンドー3DSのバーチャルコンソールでも配信されている。北米ではNES用ソフト『Crash ''n'' the Boys: Street Challenge』として発売されたが、ゲームボーイ版はありません。', 'FC-015', 12, 1, 1, 'カスタム武装アクション', 'ハチャメチャオリンピック', '', 6500, '1992-06-26', '', 'https://www.youtube.com/embed/K7kNlPlSA58', 1, 1, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (17, 'いけいけ! 熱血ホッケー部 すべってころんで大乱闘', 'イケイケ！ネッケツホッケーブスベッテコロンデダイラントウ', '「いけいけ熱血ホッケー部」は、1992年2月7日にテクノスジャパンから発売されたファミコンゲームソフトで、アイスホッケーを題材にした熱血シリーズのケンカスポーツゲームです。3人制で3分3ピリオドのゲーム形式を採用し、ショルダータックルやスティックでのはじき合い、パンチやキック、スティックでの直接的な妨害ができ、チャージ攻撃も健在。しかし、何度も攻撃されると怒り状態になり、反撃すると反則が取られペナルティを被る設定となっています。シナリオモードと対戦モードの2つが選べ、プレイヤーはキーパーを別の人が動かす二人プレイも可能。シナリオモードでは、熱血高校ホッケー部が弱小チームで次の対抗戦に敗北すると廃部が決定するという状況にあります。主人公のくにおたちは、ドッジボール部との紅白戦を計画し、さらに特訓試合をこなして、運命の対抗戦に臨む。新入部員も登場し、試合を勝ち進んでいきます。同点は敗北扱いとなるため、熱血ホッケー部は一丸となって勝利を目指すことになります。甲斐浩二氏がゲームデザインを手がけています。', 'FC-016', 12, 1, 7, 'アイスホッケー', 'ハイスピードハチャメチャホッケー', '', 6200, '1992-02-07', '', 'https://www.youtube.com/embed/a2LeWv-b69A', 1, 0, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (18, '聖闘士星矢 黄金伝説完結編', 'セイントセイヤオウゴンデンセツカンケツヘン', '『聖闘士星矢 黄金伝説』は、ファミリーコンピュータ用ゲームソフトで、車田正美の漫画およびアニメ『聖闘士星矢』を原作としています。本作は、原作の冒頭から黄金聖闘士との戦いまでを再現しています。また、前作の続編であり、黄金聖闘士が守る十二宮を突破してアテナ・城戸沙織を救うことが目的です。ステージクリア型であり、十二宮および教皇の間の全13ステージ構成になります。アクションステージと黄金聖闘士との戦闘（またはイベント）の2つの要素があり、キャラクターデザインはアニメ準拠だが、一部原作の設定が採用されています。『聖闘士星矢 黄金伝説編 Perfect Edition』は、ワンダースワン用ソフトとしてリメイクされ、2013年11月7日には、前作と本作が共にそのまま収録されたニンテンドー3DS用ソフト『バンダイナムコゲームスPRESENTS Jレジェンド列伝』が発売されました。アクションステージは、ペガサス星矢以外のキャラクターも操作可能で、ステータスは「COSMO（コスモ）」「LIFE（ライフ）」「SEVENSENSES（セブンセンシズ）」の3つで、コスモの数値が攻撃力と射程に関係し、大きいほうが有利です。また、宮に着くと、特定のステージを除き黄金聖闘士との戦闘が始まり、攻撃して敵のコスモかライフを0にすればクリアとなります。', 'FC-017', 8, 1, 1, '', '', '', 5800, '1988-05-30', '', 'https://www.youtube.com/embed/oOebtHLwKKU', 1, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (19, 'キン肉マン マッスルタッグマッチ', 'キンニクマンマッスルタッグマッチ', '「キン肉マン マッスルタッグマッチ」は、1985年にバンダイから発売されたファミリーコンピュータ用の対戦アクションゲームで、人気漫画「キン肉マン」を題材としています。このゲームは初めての対戦型格闘ゲームであり、2人対戦をコンセプトとしていました。プレミアバージョンとして、公式ゲーム大会の景品用のゴールドカートリッジ版と、集英社児童図書版の2種類があり、ゴールドカートリッジ版は、好きなキャラクターを入れる権利が与えられ、全国の8地区の上位1名に配られました。このカートリッジは希少性から100万円を超える価格でオークションに出品され、偽物も出回っています。後に、他のゲーム機や復刻版に収録されたことで、再び注目を集めました。ゲームの内容は、2人の超人がタッグを組み、パンチ、キック、バックドロップなどの技を使って戦うもので、ミート君が投げる命の玉を取ると必殺技が使用できる。片方の相手に3回勝つと1ステージクリアになる。十字キーで移動、Bボタンでジャンプ、Aボタンでパンチ、ジャンプ中にAボタンを押すことでキックが使用できるなど、シンプルな操作方法で楽しめます。', 'FC-018', 8, 1, 1, '', '対戦格闘ゲームの草分け的な存在', '', 4900, '1985-11-08', '', 'https://www.youtube.com/embed/ajoGwGvwuJ0', 1, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (20, 'まじかる☆タルるートくん FANTASTIC WORLD!!', 'マジカルタルルートクンファンタスティックワールド', '『まじかる☆タルるートくん FANTASTIC WORLD!!』は、ジャンプ作品のゲーム化作品であり、アクションゲームです。ストーリーは全8話で、ボスのいない話もあります。バッテリーバックアップが実装され、最初に名前を入れてファイルを作成してスタートします。フィールドマップには番号の付いた看板がいくつか配置されており、それに応じて横スクロールのアクションステージが用意されています。また、フィールドマップには他にも色々な物が配置されており、それぞれイベントが起こる。イベントアイテムが入っているプレゼント箱、魔法アイテムが入っているまじかるばっくん、松っつぁんが投げるたこ焼きをキャッチするミニゲームができるたこ焼きなどがあります。残機を増やす3×3のビンゴゲームができる風船も存在します。キャラクターは、チェックポイントやボス、通せんぼをしているものなど、様々です。攻撃手段は「舌」で、4方向に攻撃可能であり、水中のステージもあります。ステージ中にタルの大好物であるたこ焼きが配置されており、食べることで個数が加算されます。', 'FC-019', 8, 1, 1, '', 'まじかる☆タルるートくんを忠実に再現した良作', '', 5800, '1991-03-21', '', 'https://www.youtube.com/embed/7Pos-XA6nIc', 1, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (21, 'ゲゲゲの鬼太郎 妖怪大魔境', 'ゲゲゲノキタロウヨウカイダイマキョウ', '『ゲゲゲの鬼太郎 妖怪大魔境』は、1986年にバンダイから発売されたファミリーコンピュータ用の横スクロールアクションゲームです。原作は漫画およびアニメ作品『ゲゲゲの鬼太郎』であり、プレイヤーは主人公の鬼太郎を操作し、敵である妖怪たちを倒していく内容となっています。ステージはアクションステージがある「魔境」と砂かけ婆の家、そしてボスがいる「妖怪城」の見下ろし型マップと、妖怪と戦う横スクロールアクションステージに分かれます。魔境の水晶玉を手に入れ、ステージのボスを倒すと1ステージクリアとなります。全16ステージあり、これをクリアするとまた1ステージに戻り無限ループします。ライフ制はなく、敵妖怪や弾に当たると1人減ります。残り人数が無くなるとゲームオーバーとなり、コンティニューはできません。ステージ中の行動によっては残り人数を増やすこともできますが、残り250人を超えるとオーバーフローしてしまい、1人やられるだけで即ゲームオーバーになる現象が発生します。隠しコマンドも存在しています。また、アニメ第3期をモチーフにしたアクションゲームであり、シューティングゲームの要素もあるが、操作が非常に難しく、難易度は高いです。売り上げは100万本を超えます。', 'FC-020', 8, 1, 1, '', 'アニメ版第3期をモチーフとした横スクロールアクション', '', 4900, '1986-04-17', '', 'https://www.youtube.com/embed/nmji4WSuW-k', 1, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (22, 'SDヒーロー総決戦 倒せ!悪の軍団', 'エスディーヒーローソウケッセンタオセアクノグンダン', '「SDヒーロー総決戦 倒せ!悪の軍団」は、1990年にバンプレストからリリースされたファミリーコンピュータ用アクションシューティングゲームで、コンパチヒーローシリーズの第2弾です。マップは8つの惑星ステージで構成され、各ステージは登場するヒーローに関係した構成になっており、それにちなんだヒーローグループが初期操作キャラクターとして規定されています。8つのステージをクリアすると、最終ステージであるステージ9が現れます。ステージ9は、初期操作キャラクターが規定されていない特殊な形式で進行します。ストーリーは、SD戦士たちが平和に暮らすSDネイションに、謎のUFOが襲来して、SD戦士の母というべきガチャポンマシンとそのエンジニアであるエミィちゃんをさらわれたことから始まります。犯人は悪の帝王ダークブレインで、彼はガチャポンマシンで悪玉SDだけを増やして、SDネイションを乗っ取ろうと企んでいました。正義のSD戦士たちはガチャポンマシンとエミィちゃんを救い出し、SDネイションの平和を取り戻すために戦います。また、後に発売されたニンテンドー3DS用ソフト「ロストヒーローズ」には、本作の移植版のダウンロードコードが付属しています。', 'FC-021', 11, 1, 1, '', 'SD化されたTVキャラクター達が共演', '', 6300, '1990-07-07', '', 'https://www.youtube.com/embed/WRO0UXteuyg', 1, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (23, 'SDガンダムワールド ガチャポン戦士2 カプセル戦記', 'エスディーガンダムワールドガチャポンセンシツーカプセルセンキ', 'SDガンダムワールド ガチャポン戦士は、バンダイが発売した「SDガンダム」を題材としたファミリーコンピュータ用ウォー・シミュレーションゲーム。最も古い「SDガンダム」を題材としたコンピュータゲームであり、ウォー・シミュレーションゲームとしても最初期の作品である。1987年に第一作『SDガンダムワールド ガチャポン戦士 スクランブルウォーズ』が発売され、以降、5作品がファミリーコンピュータ用ゲームソフトとして発売された。第二作『SDガンダムワールド ガチャポン戦士2 カプセル戦記』は、1989年に発売された。本作では、従来作よりも多くのマップとユニットが追加され、A・Bボタンを同時に押すことで使用出来る武装枠が新しく設けられた。また、ユニット生産が本拠地以外の工場でも行えるようになり、工場を占領することで最大7か所でユニットの生産ができるようになった。戦闘はアクション形式によって行われ、再び同形式の戦闘が採用されるのは『SDガンダムX』を待つ事となる。', 'FC-022', 8, 1, 4, 'シミュレーション&アクション', '1対1のウォーシミュレーションゲーム', '', 6800, '1989-06-25', '', 'https://www.youtube.com/embed/LrMrOHCaA1s', 1, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (24, 'ドラゴンボール 神龍の謎', 'ドラゴンボールシェンロンノナゾ', '『ドラゴンボール 神龍の謎』は、バンダイが発売した1986年にリリースされたファミリーコンピュータ用ゲームソフトです。『ドラゴンボール』のアクションアドベンチャーゲームで、プレイヤーは主人公の孫悟空を操作して、ドラゴンボールを集め、願い事の謎を解明します。このゲームは、レッドリボン軍と戦っている悟空が主人公となっているため、原作準拠のキャラクターはレッドリボン軍のメタリック軍曹あたりまでと中途半端で、オリジナル要素が多く含まれています。ゲームの難易度は非常に高く、時間経過で徐々に体力が減っていくが、回復アイテムがなかなか手に入らず、難易度が上がります。このゲームは120万本以上の売上を記録しているが、『ドラゴンボール』を題材としたゲーム作品としては最も評価が低いとされています。本作は、ニンテンドーDS用ソフト『ドラゴンボールDS2 突撃!レッドリボン軍』やニンテンドー3DS用ソフト『バンダイナムコゲームスPRESENTS Jレジェンド列伝』などの作品に移植されました。', 'FC-0023', 8, 1, 1, '', 'ライフ回復が運次第の激ムズアクション', '', 5300, '1986-11-27', '', 'https://www.youtube.com/embed/0Fyg-XP2FPk', 1, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (25, 'ドラえもん', 'ドラエモン', '1986年12月12日にハドソンから発売されたファミリーコンピュータ用ゲームソフト『ドラえもん』は、TVアニメ『ドラえもん』（第2作第1期）を題材としたキャラクターゲームです。このゲームは、『ドラえもん のび太の宇宙開拓史』、『ドラえもん のび太の大魔境』、『ドラえもん のび太の海底鬼岩城』の3作品をモチーフにしています。プレイヤーはドラえもんを操作し、3つのワールドに分かれている各ワールドを攻略し、仲間を救出することが目的となります。各ワールドごとにシステムが異なり、ひとつの独立したゲームのようになっています。ライフ制と残機制を採用しており、ライフが0になると1ミスとなって残り人数が減少し、残り人数が0のときにミスするとゲームオーバーになります。裏技によるコンティニューが可能で、ライフはドラえもんの好物である「ドラやき」を取得することで回復します。通常はワールド1から順に進行するが、裏技によりワールド2や3からスタートさせることも可能です。ゲームクリアを達成した場合、エンディングでスタッフロールを見ることができます。また、カセットの色から「白ドラ」、メーカー名から「ハドソンのドラえもん」と呼ばれることがあります。', 'FC-024', 13, 1, 1, 'アクション&シューティング', '通称『白ドラ』の良作キャラゲー', '', 5500, '1986-12-12', '', 'https://www.youtube.com/embed/aGbgFpHOvGw', 1, 1, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (26, 'スーパーマリオワールド', 'スーパーマリオワールド', '『スーパーマリオワールド』は、任天堂が1990年に発売したスーパーファミコン用のアクションゲームで、マリオが主人公です。全世界での販売本数は累計約2061万本を記録し、日本国内では約355万本が販売された人気の作品であり、スーパーファミコンのローンチタイトルの1つです。北米版では副題がつけられず、日本の公式サイトでもタイトル名は『スーパーマリオワールド』のみとなっています。本作には、前作『スーパーマリオブラザーズ3』の飛行船の残骸という設定で、沈没船が登場します。ストーリーは、マリオたちが恐竜ランドにやってきて、ピーチ姫が行方不明になってしまったところから始まります。マリオたちは恐竜たちと協力してピーチ姫を救出する冒険を繰り広げます。本作は、後に『スーパーマリオ ヨッシーアイランド』が発売され、欧米版では『Super Mario World 2: Yoshi''s Island』となっており、本作のナンバリング続編扱いになっています。また、後に移植作品や復刻版も多数発売されており、多くのファンに愛されています。', 'SFC-001', 1, 3, 1, '', 'そして舞台は恐竜ランドへ。', '', 7700, '1990-11-21', 'https://www.nintendo.co.jp/n02/shvc/mw/index.html', 'https://www.youtube.com/embed/tWfN2aCge8U', 1, 1, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (27, 'スーパーマリオカート', 'スーパーマリオカート', '「スーパーマリオカート」は、任天堂が1992年に発売したスーパーファミコン用ゲームソフトで、マリオシリーズのキャラクター達がカートでレース＆バトルを繰り広げるゲームです。4つのモードがあり、「マリオカートGP」、「タイムアタック」、「VSマッチレース」、「バトルゲーム」が用意されており、8人のキャラクターから1人を選ぶことができます。コースは、キノコ、フラワー、スターの3つのカップにそれぞれ5コースずつ、合計15種類があり、スペシャルカップが追加されることで総数は20となっています。コインを拾うことでスピードUPするが、接触や水没・転落で失うこともあります。本作はシリーズ中唯一、ゲーム中の画面が上下2分割されており、2人でプレイすることを重視しているためである。復刻版も発売され、現在でも人気があります。', 'SFC-002', 1, 3, 10, 'アクションレースゲーム', 'シリーズでおなじみのキャラがカートレースで勝負', '', 8600, '1992-08-27', 'https://www.nintendo.co.jp/n02/shvc/mk/index.html', 'https://www.youtube.com/embed/k9gniCkqp1c', 1, 0, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (28, 'スーパーマリオRPG', 'スーパーマリオアールピージー', '『スーパーマリオRPG』は、任天堂とスクウェア（現：スクウェア・エニックス）が共同制作したアクションRPGであり、1996年に発売されました。\r\n本作は、任天堂のマリオシリーズ初のRPG作品であり、広く知られたマリオシリーズの世界観を用いつつ、アクションゲームであるシリーズの特色を活かした作りと独特なシナリオにより、シリーズ作品としてもRPG作品としても異色の作風となっています。また、クォータービューによる立体構成のフィールドを基礎としつつ、アクションゲームであるシリーズの特長を活かして随所にアクションを取り入れた点が最大の特徴となっています。\r\n本作は、マリオシリーズとして初めて本格的なストーリー性を持っており、シリーズの主要登場人物であるクッパ・ピーチの性格はこの作品においてほぼ完成されたとされます。本作の音楽・作曲は、マリオシリーズを手がけている近藤浩治ではなく、当時スクウェアの社員であった下村陽子が担当しました。本作は、特典としてスーパーファミコン本体を4000円安く購入できる割引クーポンが付属し、敵キャラであるパックンフラワーが歌うテレビCMも人気を集めた。本作は、特殊チップ、SA-Iをソフトに搭載しており、レンダリングされた3Dマリオの演出など、高品質なグラフィックが表現されています。本作は、マリオシリーズのRPG作品としてペーパーマリオシリーズとマリオ&ルイージRPGシリーズがそれぞれ登場しており、国内外で高い評価を得ています。', 'SFC-003', 1, 3, 3, 'アクションRPG', 'ロールプレイングゲームやったことないひとも', '', 7500, '1996-03-09', 'https://www.nintendo.co.jp/n02/shvc/p_arwj/index.html', 'https://www.youtube.com/embed/f8qo53npZt4', 1, 1, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (29, 'ドラゴンクエストI・II', 'ドラゴンクエストワンツー', '「ドラゴンクエストI・II」は、エニックス（現：スクウェア・エニックス）がリリースしたRPGゲームソフトで、日本では1993年にスーパーファミコン用、1999年にゲームボーイ用として発売されました。\r\n北米でも2000年にゲームボーイ用ソフト『Dragon Warrior I & II』として発売されています。本作は、ファミリーコンピュータ用に発売された「ドラゴンクエスト」シリーズのリメイク版で、第1作『ドラゴンクエスト』（以降『I』）と第2作『ドラゴンクエストII 悪霊の神々』（以降『II』）を1つのソフトにまとめたものです。世界観やストーリーは、旧作とほとんど変更がないが、操作性は向上しています。また、ゲームバランス面で細かい調整が加えられ、プレイしやすくなっています。『I』『II』のどちらからでもプレイ可能で、冒険の書（セーブファイル）も各作品ごとに3つまで作成できます。キャッチコピーは「目を開けて夢を見よ」。', 'SFC-004', 10, 3, 3, '', '目を開けて夢を見よ', 'スーパーファミコンで伝説は進化する。', 9600, '1993-12-18', 'https://www.jp.square-enix.com/game/detail/dq1-2/', 'https://www.youtube.com/embed/PNmaBW851oQ', 1, 1, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (30, 'ドラゴンクエストIII そして伝説へ…', 'ドラゴンクエストスリーソシテデンセツヘ', '「ドラゴンクエストIII そして伝説へ…」は、1996年12月6日にエニックスから発売された、スーパーファミコン用のゲームソフトであり、ドラゴンクエストシリーズのリメイク作品です。この作品は、FC版に基づいているが、ストーリー、キャラクター操作、コマンド操作に大幅な要素の追加・変更が施されました。アイテムが多数増加し、中には発売当時の流行を反映したアイテムも登場しました。男性キャラクター専用装備品も追加され、武器も単体攻撃武器以外にも全体攻撃武器やグループ攻撃武器が追加されました。オープニング、ダーマ神殿での「遊び人」への転職、隠しダンジョンが追加されました。画面仕様やキャラクター操作、コマンド操作は、前年に発売された SFC版『ドラゴンクエストVI』をベースにしており、従来の預かり所をゴールド銀行へ変更し、人々の会話の記憶機能があり、世界地図、ちいさなメダル、鍵無しで開く扉、井戸に入ることができるなどの要素も追加されました。本作では、「ふくろ」の中にあるアイテムは、移動中に限りふくろから出さずに使うこともできるようになり、アイテムを仲間に渡す際にその位置も指定できるようになっています。また、装備可能なアイテムの入れ替えが可能になりました。', 'SFC-005', 10, 3, 3, '', '画面の中に、あなたがいる。', 'SFC究極のドラクエ', 8700, '1999-12-06', 'https://www.jp.square-enix.com/game/detail/dq3/', 'https://www.youtube.com/embed/JssadoWTsFA', 1, 1, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (31, 'ドラゴンクエストV 天空の花嫁', 'ドラゴンクエストファイブテンクウノハナヨメ', '「ドラゴンクエストV 天空の花嫁」は、1992年にエニックスから発売されたスーパーファミコン用ロールプレイングゲームで、「ドラゴンクエストシリーズ」の第5作目にあたります。親子3代に渡るストーリーや結婚という人生の重要なイベントがあり、モンスターを仲間にするシステムが導入されたのが特徴です。また、父と息子の絆、妻と出会い、子どもたちが成長するストーリーも展開されます。堀井雄二氏は、「感動であり、もう一つの人生を体験すること」と述べています。本作はゲームブック、小説、漫画、ドラマCD、映画など多くのメディア展開があり、リメイク版もPlayStation 2版、ニンテンドーDS版、スマートフォン版が発売されています。海外では2009年に北米や欧州で発売され、ゲーム誌「ファミ通」の「クロスレビュー」ではスーパーファミコン版、ニンテンドーDS版はプラチナ殿堂、PlayStation 2版はゴールド殿堂を獲得しました。', 'SFC-006', 10, 3, 3, '', '愛がある、冒険がある、人生がある', '', 9600, '1992-09-27', 'https://www.jp.square-enix.com/game/detail/dq5/', 'https://www.youtube.com/embed/uYvmu-qJwu0', 1, 1, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (32, 'ドラゴンクエストVI 幻の大地', 'ドラゴンクエストシックスマボロシノダイチ', '『ドラゴンクエストVI 幻の大地』は、1995年12月9日に日本のエニックスから発売されたスーパーファミコン用ロールプレイングゲームであり、『ドラゴンクエストシリーズ』の第6作目です。天空シリーズの3作目であり、完結編として位置づけられています。本作はもう一つの世界「幻の大地」を舞台にし、主人公が大魔王を討伐して世界を救う物語です。ゲームシステムとしては、転職システム、2つの世界を往復するシナリオ、モンスターを仲間にするシステムが特徴的です。開発はハートビートが行い、プロデューサーは千田幸信、ゲーム・デザインとシナリオは堀井雄二、キャラクター・デザインは鳥山明、音楽はすぎやまこういち、ディレクションおよびプログラムは山名学が担当しました。本作はSFC版、DS版、スマートフォン版があり、日本国内での売上本数は約320万本であり、スーパーファミコン用ソフトとしては歴代3位の記録を持ちます。また、ゲーム誌『ファミ通』の「クロスレビュー」では、スーパーファミコン版およびニンテンドーDS版共にゴールド殿堂を獲得しました。', 'SFC-007', 10, 3, 3, '', 'DQを超えるのはDQだけ', '', 11400, '1995-12-09', 'https://www.jp.square-enix.com/game/detail/dq6/', 'https://www.youtube.com/embed/ym89IEj9xbY', 1, 1, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (33, 'トルネコの大冒険 不思議のダンジョン', 'トルネコノダイボウケンフシギノダンジョン', '「トルネコの大冒険 不思議のダンジョン」は、1993年にチュンソフトから発売されたスーパーファミコン用ゲームソフトであり、ダンジョンRPGのジャンルに属します。本作は「ドラゴンクエストシリーズ」の外伝的作品であり、主人公である武器商人トルネコの後日譚を描いています。本作の敵キャラクターは、同シリーズに登場したモンスターたちであり、同じく同シリーズに登場したアイテムや呪文も登場するなど、同シリーズの世界設定を踏襲しています。本作のキャッチコピーは「1000回遊べるRPG」です。\r\n本作はチュンソフトの「不思議のダンジョン」シリーズの第1作であり、後に同じシステムを使用した続編として「不思議のダンジョン2 風来のシレン」が発売されました。また、本作のストーリーの流れを汲む「トルネコの大冒険」シリーズの続編としても、「ドラゴンクエストキャラクターズ トルネコの大冒険2 不思議のダンジョン」や「ドラゴンクエストキャラクターズ トルネコの大冒険3 不思議のダンジョン」が発売されました。本作のダンジョン内の楽曲は全て、「ドラゴンクエストIV」で登場したトルネコのテーマ「武器商人トルネコ」のアレンジで構成されています。', 'SFC-008', 14, 3, 3, 'ローグライクRPG', '1000回遊べるRPG', '', 9600, '1993-09-19', '', 'https://www.youtube.com/embed/PKqWzZBcJ5E', 1, 0, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (34, 'スーパーマリオコレクション', 'スーパーマリオコレクション', '『スーパーマリオコレクション』は、1993年に任天堂がスーパーファミコン用に発売したゲームソフトで、ファミリーコンピュータの発売10周年を記念して制作されました。収録されているのは、『スーパーマリオブラザーズ』、『スーパーマリオブラザーズ2』、『スーパーマリオUSA』、『スーパーマリオブラザーズ3』の4作品です。これらは、高画質・高音質にバージョンアップされ、セーブバックアップ機能も付いている。欧米では『Super Mario All-Stars』というタイトルで発売された他、スーパーファミコン本体同梱限定版には『スーパーマリオワールド』のリメイク版も追加されています。また、ゲームボーイアドバンスの『スーパーマリオアドバンス』シリーズは、本作『コレクション』のリメイク版『USA』や『3』をベースにして、追加要素を加えた移植となっています。『スーパーマリオコレクション』は、単品において最も売れたリメイク作品であり、2020年にはマリオの35周年を記念して『スーパーマリオ 3Dコレクション』が発売されました。', 'SFC-009', 1, 3, 1, '', 'ようこそ ぼくらの同窓会へ。', '', 9500, '1999-07-14', 'https://www.nintendo.co.jp/n02/shvc/4m/index.html', 'https://www.youtube.com/embed/II3wwasuuwA', 1, 1, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (35, 'スーパーボンバーマン', 'スーパーボンバーマン', '1993年4月28日にハドソンから発売されたスーパーファミコン用アクションゲーム『スーパーボンバーマン』は、ハドソンのボンバーマンシリーズ第7作目であり、スーパーファミコンにおけるボンバーマンシリーズ第1作目です。ノーマルゲームにおいて初めて2人同時プレイが可能となった他、これまでのシリーズではノーマルゲームにおいて1ステージに1つまでしかアイテムが出現しなかったが、本作以降の作品では1つのステージに複数のアイテムが出現するようになりました。ストーリーは、悪の権力者カラット・ダイヤモンドと科学者Dr.ムックがロボットトーナメントを開催している近代都市「ダイヤモンドシティ」で、ボンバーマンを捕まえるためにメカボンバーを造り、ピースタウンへ向かったところから始まります。ボンバーマンの敵ロボット軍団がピースタウンに押し寄せる中、黒ボンバーマンは白ボンバーマンにダイヤモンドの野望を話し、一致団結します。ノーマルゲームには全部で6ステージがあり、各ステージは8つのエリアで構成されています。爆風や敵、攻撃トラップに当たると「ミス」となり、残機が減ります。コンティニューも可能です。', 'SFC-010', 13, 3, 1, '', 'ボンバーマンシリーズの金字塔', '', 7800, '1993-04-28', '', 'https://www.youtube.com/embed/yvmvQlI6sL0', 1, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (36, 'スーパーボンバーマン2', 'スーパーボンバーマンツー', '『スーパーボンバーマン2』は、1994年に発売されたスーパーファミコン用パズルアクションゲームであり、『ボンバーマンシリーズ』の第9作目かつスーパーファミコン用ソフトの第2作目です。主人公のボンバーマンを操作し、「凶悪ボンバー5人衆」を倒して地球の平和を守ることが目的である。本作は、後のシリーズ作品にも多く登場する「凶悪ボンバー5人衆」が初登場した作品であり、バトルゲームにも後のシリーズにも引き継がれる要素が多く追加されました。\r\n\r\nプロデュース！が開発し、前作を手掛けた平井隆之がゲームプランナー、鈴木俊之がプログラム、福田裕彦が音楽を担当しています。本作には非売品の『スーパーボンバーマン2 キャラバン用体験版』が存在し、キャラバン主催のイベント大会で賞品としてもらえました。ゲーム内容は、ノーマルゲームでボンバーマンを操作して数々のステージをクリアし、「凶悪ボンバー5人衆」と戦う。全5ステージ構成で、1ステージは7エリアに分かれています。各ステージの最後はボスとの対決で、メカ戦となっています。ゴールの扉が開かれる条件は、「エリア内の全ての敵を倒し」、かつ「エリアに点在するカプセルを爆風で破壊する」ことであるが、この条件を満たす前にゴールの扉に爆風を当てると、そのエリアの敵が復活します。ステージ3以降ではカプセルが爆風を当てる度に点灯と消灯が切り替わるようになっているなど、パズル要素も含まれています。本作では1人プレイ専用であり、敵に触れたりトラップにかかったりするとボンバーマンストックが減り、さらに一部のアイテムの効果がなくなってしまいます。ボンバーマンストックがなくなるとゲームオーバーとなります。', 'SFC-011', 13, 3, 1, '', 'ゴールデンボンバーが初登場', '', 8500, '1994-04-28', '', 'https://www.youtube.com/embed/O_Ra5uOBw2Q', 1, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (37, 'スーパーボンバーマン3', 'スーパーボンバーマンスリー', '『スーパーボンバーマン3』は、1995年にハドソンから発売されたアクションゲームであり、『ボンバーマンシリーズ』第13作目であり、スーパーファミコンでのボンバーマンシリーズの第4作目です。このゲームはスーパーファミコンで初めて5人同時プレイが可能になりました。『スーパーボンバーマン』以来、2人同時プレイが可能になり、「みそボン」システムも初登場しました。本作は、前作が外注だったが、再びハドソン自身が開発を行った。また、本作品を境に、ボンバーマンやバグラーなどの主要キャラクターのデザインやアートワークの作風が確立されました。本作は、PCエンジン版とスーパーファミコン版の両方の良い所を取り入れた結果、両者が融合した形となりました。', 'SFC-012', 13, 3, 1, '', 'PCエンジンシリーズとの統合', '', 8900, '1995-04-28', '', 'https://www.youtube.com/embed/p4zlw5jDGOQ', 1, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (38, 'スーパーボンバーマン4', 'スーパーボンバーマンフォー', '「スーパーボンバーマン4」は、日本のハドソン社が1996年に発売した固定画面アクションゲームで、同社の「ボンバーマンシリーズ」のスーパーファミコン用ソフト第5作目です。主人公の「ボンバーマン」は、未来を支配しようとしている悪の天才科学者「バグラー」の野望を阻止するために操作します。本作は「ボンバースロー」、「ボンバープッシュ」、「デンジャラスボム」などの新要素が追加されました。プロデューサーは小崎整、ゲーム・デザインは平井隆之、音楽は竹間淳が作曲し、福田裕彦が編曲を担当しています。アートデザインは水野祥司と吉見直人が担当しました。ノーマルゲームでは、8つのエリアで構成される全5ステージを進み、敵を倒すことでワープゲートに入ることでクリアします。ステージクリア後に遊ぶこともできます。ミスになる条件がいくつかあり、残機が減り、ボムアップ・ファイアー・スピードアップ以外のアイテムの効果が失われます。', 'SFC-013', 13, 3, 1, '', '新要素は盛り沢山でパワーアップ', '', 7777, '1996-04-26', '', 'https://www.youtube.com/embed/Z21UIAf9Fic', 0, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (39, 'スーパーボンバーマン5', 'スーパーボンバーマンファイブ', '「スーパーボンバーマン5」は、1997年2月28日に発売されたアクションゲームで、スーパーファミコンのボンバーマンシリーズの最終作（第7作目）です。竹間淳、福田裕彦、松前公高、水野祥司、吉見直人、佐藤梢が音楽、編曲、アートデザインを担当しています。このゲームには、最初からすべての隠し要素が使える限定版のゴールドメッキ版も存在します。\r\n\r\n「スーパーボンバーマン5」は、ボンバーマンを操作し、爆弾を使って多くのステージをクリアしていく「ノーマルゲーム」と、2人で対戦する「バトルゲーム」の2つのモードがあります。「ノーマルゲーム」では、新しいステージに加えて、「スパボン1〜4」のステージを追体験することができ、総ステージ数は100以上になっています。ワープホールが複数出現するため、番号順に進む必要はなく、選んだワープホールによって次のステージが変化することがあります。2人同時プレイも可能で、アイテムが豊富ですが、ほとんどのボスのHPが増えています。\r\n\r\n「バトルゲーム」では、「みそボンドッジシステム」と呼ばれる仕組みによって、相手を倒してもステージ上に復帰できるようになっています。また、「ランダムサドンデス」と呼ばれる新しい要素が追加されており、プレッシャーブロックの落下パターンがランダムに決定されます。\r\n\r\n乗り物キャラクター「ルーイ」が再登場した「スーパーボンバーマン5」は、ボンバーマンシリーズのファンにとっては欠かせない作品であると言えます。', 'SFC-014', 13, 3, 1, '', 'スーパーボンバーマンシリーズの集大成', '', 6980, '1997-02-28', '', 'https://www.youtube.com/embed/RRNsXs3c5hA', 0, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (40, 'スーパーストリートファイターII', 'スーパーストリートファイターツー', '「ストリートファイターII」の後継基板「CPシステムII」である「ストリートファイターIIダッシュターボ」と並行して開発され、1年以上の時間をかけて制作された「ストリートファイターIIダッシュ」は、ストリートファイターIIのニューバージョンであり、前作に加えて4人の新キャラクターが追加され、16人のキャラクターから1人を選び、8人のキャラクターと四天王4人を倒すことが目的です。基本システムはストリートファイターIIを踏襲しており、新しく導入された機能としては、最初の一撃、連続攻撃（コンボ）、リバーサル、気絶からの復帰などがあり、これらを達成することでボーナスポイントがもらえます。また、気絶状態の種類が4種類に増え、回復にかかる時間は天使が一番短く、死神が一番長くなりました。キャラクター数が増えたため、CPU戦は、ランダムに選ばれた8人と四天王の計12名という形式に変更され、また、専用基板4枚を接続してプレイ可能なトーナメント対戦モードが導入され、全員が1回戦・準決勝・決勝戦及びそれぞれの順位決定戦の計3試合を行うスイスドロー方式で行われました。キャラクターについては、通常技が四天王に追加されたほか、新必殺技は削除または変更されました。', 'SFC-015', 15, 3, 9, '', '大幅進化したストリートファイターⅡ', '', 10900, '1994-06-25', '', 'https://www.youtube.com/embed/r0hdCFf6Bh4', 1, 1, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
