INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (971, 'LOST JUDGMENT：裁かれざる記憶', 'ロストジャッジメントサバカレザルキオク', '', 'PS5-013', 4, 12, 1, '', '', '', 8290, '2021-09-24', '', '', 0, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (972, 'デビル メイ クライ 5 スペシャルエディション', 'デビルメイクライファイブスペシャルエディション', '\r\n『デビルメイクライ5』は、カプコンが制作したデビルメイクライシリーズのナンバリングタイトル第5作目のスタイリッシュアクションゲームです。2019年3月8日にPlayStation 4、Xbox One、Steamで世界同時に発売され、次世代機向けの『5SE』も同日に発売されました。グラフィックはフォトリアルな表現で、実在の俳優の顔をモデルにしたキャラクターも登場します。ゲーム本編の前には補完ストーリーの小説や漫画も展開されました。主人公のネロとダンテに加え、謎の男Vからなる3人のプレイアブルキャラクターが楽しめる作品です。', 'PS5-014', 15, 12, 1, 'スタイリッシュアクション', 'さらに美しく。もっとクレイジーに。', '', 4990, '2020-11-12', 'https://www.devilmaycry.com/5se/jp/', 'https://www.youtube.com/embed/0zRRVG1Uhao', 0, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (973, 'Tales of ARISE', 'テイルズオブアライズ', '『テイルズ オブ アライズ』は、バンダイナムコエンターテインメントが制作したゲームソフトで、2021年9月9日に発売されました。この作品は『テイルズ オブ シリーズ』の一部であり、公式ジャンル名は「心の黎明を告げるRPG」となっています。対応プラットフォームはPlayStation 4、PlayStation 5、Xbox One、Xbox Series X/S、Microsoft Windows（Steam）です。\r\n\r\n『テイルズ オブ アライズ』は他のシリーズ作品とは異なり、舞台や設定を共有せず、完全に新しいタイトルとなっています。例えば、『エクシリア』と『エクシリア2』や、『ゼスティリア』と『ベルセリア』のような関係性はありません。\r\n\r\n最初はシリーズの25周年である2020年に発売予定でしたが、延期があり、最終的に2021年9月9日に発売されました。', 'PS5-015', 24, 12, 3, '', '令和初のテイルズオブシリーズ', '', 7980, '2021-09-09', 'https://toarise.tales-ch.jp/', 'https://www.youtube.com/embed/b_mjOItr_nY', 0, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (974, 'ELDEN RING', 'エルデンリング', '『ELDEN RING』は、フロム・ソフトウェアが開発し、2022年2月25日に発売されたオープンワールドのアクションRPGです。このゲームは、バンダイナムコエンターテインメントが海外での販売を担当しています。対応プラットフォームはPlayStation 4、PlayStation 5、Xbox One、Xbox Series X/S、Windows（Steam）です。\r\n\r\n本作はE3 2019のXbox E3 2019ブリーフィングで発表されました。ディレクターには『DARK SOULS』や『SEKIRO: SHADOWS DIE TWICE』などを手がけた宮崎英高が就任し、世界観の構築には『氷と炎の歌』の作者であるジョージ・R・R・マーティンも参加しています。\r\n\r\n『ELDEN RING』は、『DARK SOULS』シリーズの王道進化を目指して開発が始まりました。従来のゲームの要素を受け継ぎながらも、シームレスなオープンフィールドやステルス、ジャンプ、騎乗動物を利用した移動、時間や天候の変化などの新たな要素が取り入れられています。ゲーム全体の規模としても、フロム・ソフトウェア史上最大の作品となっています。', 'PS5-016', 73, 12, 3, 'アクションRPG', '王となれ', '', 8400, '2022-02-25', 'https://www.eldenring.jp/', 'https://www.youtube.com/embed/TeYTURU_kVA', 0, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (975, 'ENDER LILIES： Quietus of the Knights', 'エンダーリリーズキュータスザナイツ', '『ENDER LILIES: Quietus of the Knights』は、2Dアクションゲームであり、2021年1月にSteamでアーリーアクセスが開始され、その後、同年6月に正式な販売が行われました。このゲームは、パブリッシャーのBinary Haze Interactiveにとって、自社から初めてリリースされるタイトルとなりました。\r\n\r\nなお、このゲームは人気の高いジャンルであるメトロイドヴァニアに該当しており、海外で人気がありますが、パブリッシャーであるBinary Haze Interactiveおよび開発を担当したLive WireとAdglobeは、いずれも『エストポリス伝記』などで知られるネバーランドカンパニーの元スタッフが中心になって設立された国内の会社です。つまり、このゲームはれっきとした国産タイトルであることをご理解ください。', 'SW-034', 74, 7, 1, '', '絶望の世界で 呪いの運命にあらがう少女と騎士', '', 3480, '2022-03-24', 'https://ja.enderlilies.com/', 'https://www.youtube.com/embed/WxDAm5hRNqA', 0, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (976, 'ダービースタリオン', 'ダービースタリオン', '『ダービースタリオン』は、パリティビットが製作著作し、ゲームアディクトが発売したNintendo Switch向けの競馬シミュレーションゲームです。\r\n\r\nこのゲームは、『ダービースタリオン マスターズ』以来4年ぶりのダービースタリオンシリーズの最新作であり、コンソール向けとしては『ダービースタリオンGOLD』以来6年ぶり、据置機向けとしては『ダービースタリオン04』以来17年ぶりの登場となります。また、このゲームは初めてHD解像度に対応しており、Switchのテーブルモードや携帯モード（ドック非接続時）でプレイする場合は1280×720の高画質で楽しむことができます。\r\n\r\nさらに、2021年12月17日には大型アップデート（Ver1.1.0）が実施されました。このアップデートにより、新たな要素や改善が導入され、ゲームのバージョンアップが行われました。', 'SW-035', 75, 7, 4, '', '正統進化した「ダービースタリオン」', '', 7800, '2020-12-03', 'https://www.gameaddict.co.jp/derbystallion/', 'https://www.youtube.com/embed/mbERrnvsbcs', 0, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (977, 'くにおくんの三国志だよ全員集合!', 'クニオクンノサンゴクシダヨゼンインシュウゴウ', '\r\n「くにおくんの三国志だよ全員集合!」は、くにおくんシリーズの35周年記念作品であり、コメディアクションゲームです。物語は桃園の誓いから赤壁の戦いまでの三国志を舞台にしており、くにおくんシリーズのメンバーたちが大暴れします。\r\n\r\nこのゲームの音楽は、くぼたあきゆき氏（『キルラキル ザ・ゲーム -異布-』の制作にも関わった方）とfurani氏（『熱血硬派くにおくん外伝 イカすぜ！小林さん』などを手がけた方）が担当しています。\r\n\r\nサウンドトラックは一般販売されておらず、ビックカメラのパッケージ版予約特典として「オリジナル＆アレンジBGM聞き比べサウンドトラック」という非売品CDが存在します。このCDには、ゲーム用にアレンジされた曲とその原曲が交互に収録されており、両方の曲を聞き比べながら楽しむことができます。', 'SW-036', 53, 7, 1, '', 'くにおくん×三国志', '', 3400, '2022-07-21', 'https://www.kuniokun.jp/3594saga/', 'https://www.youtube.com/embed/Aee546svWwQ', 0, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (978, 'HADES', 'ハデス', '『HADES』（ハデス）は、Supergiant Gamesが開発・販売したアメリカ合衆国のゲームソフトです。ギリシア神話をテーマにしたローグライク・アクションRPGです。\r\n\r\n『HADES』は、英国アカデミー賞のベストゲーム賞やThe Game Awardsのベストインディーゲーム賞、ネビュラ賞のゲームライティング部門など、多くの賞を受賞しています。また、販売本数も100万本を超えています。\r\n\r\n2018年12月にはPC版がEpic Gamesストアでアーリーアクセスとして限定的に発売され、2020年9月にはNintendo Switch版がアーリーアクセスを終了して発売されました。さらに、2021年8月にはPS4・PS5・Xbox One・Xbox Series X/S版も発売されました。\r\n\r\n最初は日本語非対応でしたが、ローカライザーのハチノヨンによる翻訳により、2021年4月にはPC版が日本語に対応し、2021年6月にはSwitch版、2021年8月にはXbox系列、2021年9月にはPS系列の日本語版が発売されました。\r\n\r\n物語は、冥王ハデスが支配する冥界を舞台にしています。ハデスの息子であるザグレウスは、冥界からの脱出を試みる「家出」を日常的に行っています。彼には特別な背景があります。\r\n\r\nプレイヤーはザグレウスを操作し、冥界のダンジョンでモンスターやトラップに満ちた中からの脱出を目指します。HPがなくなるたびに、スタート地点であり拠点でもある「ハデスの館」から再挑戦します。挑戦するたびに、ダンジョンの構造や入手できるアイテムが変化します。\r\n\r\n挑戦を繰り返す中で、ハデスの館やダンジョンにいる個性豊かなキャラクターとの会話を通じて物語が展開されます。', 'SW-037', 76, 7, 3, '', 'ギリシア神話をテーマにしたローグライク・アクションRPG', '', 3000, '2021-09-30', 'https://www.supergiantgames.com/games/hades/', 'https://www.youtube.com/embed/_CkWv1WPCCg', 0, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (979, 'UNDERTALE', 'アンダーテール', '\r\n『Undertale』（または『UNDERTALE』、アンダーテールまたはアンダーテイル）は、トビー・フォックス（Toby Fox）によって制作されたアメリカ合衆国のコンピュータRPGです。\r\n\r\n2015年9月15日に、Microsoft WindowsおよびmacOS向けに発売されたインディーゲームで、日本を含む他の地域でも移植版が発売されました。\r\n\r\n本作は、隔離された地底世界（the Underground）が舞台の物語です。プレイヤーは「ニンゲン」の子供として地底世界に迷い込み、地上に戻るためにモンスターたちと出会い、ふれあいながら冒険を進めます。\r\n\r\nこのゲームは「誰も死ななくていいやさしいRPG」というキャッチコピーを掲げており、モンスターを倒す必要がないという特徴があります。通常のゲームとは異なり、モンスターと戦闘するか、話しかけたり他の方法で平和的に解決するかを選択することができ、その選択によってゲームの進行やエンディングが変化します。\r\n\r\n本作は、一般的なRPGのバトルシステムにシューティングゲームの要素を組み合わせた独自のシステムを採用しており、「2DシューティングRPG」とも呼ばれます。また、レトロゲーム風の温かみのあるグラフィックや独特な世界観、個性的なキャラクターも魅力の一つです。\r\n\r\n『Undertale』は、アメリカの作曲家兼ゲーム開発者であるトビー・フォックスによってほぼ1人で開発されたインディーズタイトルです。製作資金はクラウドファンディングで調達され、2年以上の時間をかけて制作されました。トビー・フォックスは、コメディ番組『Mr.ビーン』や日本のゲーム作品『MOTHERシリーズ』、『マリオ&ルイージRPGシリーズ』、『東方Project』、『真・女神転生』、『ブランディッシュ』、『洞窟物語』から影響を受けていると述べています。', 'SW-038', 77, 7, 3, '', '誰も殺さなくたっていいRPG', '', 4000, '2018-09-15', 'https://undertale.jp/', 'https://www.youtube.com/embed/fsKLv0YbAU4', 0, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (980, '魔界戦記ディスガイア7', 'マカイセンキディスガイアセブン', '\r\n『魔界戦記ディスガイア7』は、前作の発売から1年半後の2022年8月に製作が発表され、ほぼ半年後の2023年1月26日に発売されました。前作『6』がシリーズファンにとって不評だったことや、シリーズのプロデューサーであった新川宗平氏が発表直前に一身上の都合により退任したことから、多くの人々が本作の出来に不安を抱いていました。しかし、発表会では「『6』の評価が芳しくないこと」を意識し、「（シリーズの傑作とされる）『5』をベースにしてバランス調整を行う」という方針が発表されました。\r\n\r\n結果として、本作ではその言葉通りに、ゲームバランスは『5』を基にして作られ、『6』のシステムはごく一部を除いて継承されていません。これにより、シリーズファンにとって期待された良質なゲーム体験が提供されています。', 'SW-039', 48, 7, 3, 'シミュレーションRPG', '今度の舞台は和風の魔界！', '', 6980, '2023-01-26', 'https://disgaea.jp/7/', 'https://www.youtube.com/embed/jHb5W8d71hs', 0, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (981, 'メガトン級ムサシ', 'メガトンキュウムサシ', '『メガトン級ムサシ』は、レベルファイブが制作したコンピュータゲームおよびそれに登場するロボット兵器を含むメディアミックスコンテンツです。ゲーム版はNintendo SwitchとPlayStation 4向けに2021年11月11日に発売されました。当初はiOS/AndroidやPlayStation 5でも発売予定でした。2022年7月には、新たなストーリーや対人戦などの追加要素を含んだ最新作『メガトン級ムサシX』が発表され、2022年12月1日に基本無料でプレイできる配信が開始されました。\r\n\r\nさらに、2023年3月9日には「LEVEL5 VISION 2023 鼓」というイベントで、国際版である『メガトン級ムサシW: WIRED』が発表され、新たにPC向けの配信（Steam）も予定されています。', 'SW-040', 49, 7, 3, '', '鋼鉄のサムライ出陣', '', 6340, '2021-11-11', 'https://www.megaton-musashi.jp/mm/', 'https://www.youtube.com/embed/yNYux0LLZvQ', 0, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (982, 'ルーンファクトリー5', 'ルーンファクトリーファイブ', '『ルーンファクトリー5』は、前作『ルーンファクトリー4』を手掛けた開発会社であるネバーランドカンパニーが解散し、続編の希望が絶たれていたと思われていた中で、まさかの完全新作として登場しました。\r\n\r\nこの驚きの発表は、2019年のNintendo Directにて行われ、シリーズのファンたちを大いに喜ばせました。しかし、実際にプレイしてみると、その実態は...\r\n\r\n『ルーンファクトリー5』は、前作『4』のシステムを踏襲しており、RPGおよび農業のUIや操作性は基本的に『4』のものに似ていますが、いくつかの変更もあります。\r\n\r\n主人公は男性と女性から1人を選ぶ方式で、選ばなかった方の主人公はゲーム内に登場しません。また、シリーズとしては初めてCERO:B（12歳以上対象）のレーティングを受けています。', 'SW-041', 27, 7, 4, 'ファンタジー生活ゲーム', 'ルーンファクトリー新章始まる', '', 6980, '2021-05-20', 'https://runefactory.marv.jp/series/rf5/', 'https://www.youtube.com/embed/Im1z6RHiVoQ', 0, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (983, '熱血硬派くにおくん外伝 リバーシティガールズ1・2', 'ネッケツコウハクニオクンガイデンリバーシティーガールズワンツー', '『熱血硬派くにおくん外伝 リバーシティガールズ1・2』は、伝説的なベルトスクロールアクションゲームである『くにおくんシリーズ』に新たな息吹を与えた作品です。これは、前作『熱血硬派くにおくん外伝 River City Girls』の続編として開発されました。\r\n\r\nプレイヤーは、前作同様にみさこときょうこという二人のヒロインたちとなり、リバーシティという場所をさらにカオスになってしまった状況から救うための冒険に身を投じます。彼女たちは前作以上にハチャメチャな活躍を見せながら、様々な困難に立ち向かっていきます。\r\n\r\nこのゲームは、くにおくんシリーズの伝統を受け継ぎながらも新たな要素を取り入れ、爽快なアクションと共にストーリーを進めることが特徴です。プレイヤーは美しいピクセルアートの世界で、熱い戦いと友情を体感することができます。', 'SW-042', 53, 7, 1, '', '女の子だからって、なめんなよ', '', 4800, '2022-12-01', 'https://www.kuniokun.jp/rcg/', 'https://www.youtube.com/embed/atTNQVeg8Vw', 0, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (984, '剣と魔法と学園クエスト。', 'ケントマホウトガクエンクエスト', '編集中', 'SW-044', 46, 7, 3, '', '「剣と魔法と学園」の世界で繰り広げられる本格ストラテジーRPG', '', 5436, '2022-09-08', 'https://totomono.acquire.co.jp/quest/', 'https://www.youtube.com/embed/Q2J4Ym4HlYU', 0, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (985, '海腹川背 BaZooKa!', 'ウミハラカセバズーカ', '\r\n『海腹川背 BaZooKa!』は、2020年5月28日にサクセスからNintendo SwitchとPlayStation 4向けに発売されたゲームソフトです。このゲームは、固定画面型のアクションゲームとして、ゲームジャンルが変更されました。\r\n\r\nプレイアブルキャラクターとしては、シリーズキャラクターだけでなく、サクセスやスタジオ最前線のIPタイトルからもキャラクターが選択できます。さらに、YouTuberのドズルもプレイヤーキャラクターとして選ぶことができます。\r\n\r\nゲームでは、最大4人までの協力プレイや対戦プレイがオフラインとオンラインの両方で可能です。ただし、PlayStation Storeにおいて「1人のプレーヤー・4人のネットワークプレーヤー」と誤って表記されている情報がありますが、これは誤りです。', 'SW-045', 78, 7, 1, 'ラバーリング・アクションゲーム', 'こんどの海腹川背はeスポーツ！？', '', 2800, '2020-05-28', 'https://swninfo.success-corp.co.jp/general/umihara-bazooka/', 'https://www.youtube.com/embed/CXVFBH0Dvec', 0, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (986, '海腹川背 Fresh!', 'ウミハラカワセフレッシュ', '『海腹川背 Fresh!』は、2019年4月25日にNintendo Switch向けにサクセスから発売されたゲームソフトです。その後、2020年4月23日にPlayStation 4版、同年5月28日にSteam版がリリースされました。\r\n\r\nこのゲームでは、ステージクリア制からクエストクリア制へと変更されています。また、発売元であるサクセスのIPタイトルである『コットン』の主人公である“ナタ・デ・コットン”がプレイアブルキャラクターとして選択できます（最初は特定のクエストクリア後に解禁されますが、後にショップでも解禁可能になりました）。さらに、7月には『洞窟物語』のキャラクターである“カーリー”も選択できるようになりました。\r\n\r\nそして、2020年にはアーケード版の『海腹川背 Fresh! for AC』が発表され、ALL.Net P-ras MULTI Ver.3にて稼働を開始しました。これは初めてのアーケード向けタイトルとなりました。', 'SW-046', 78, 7, 1, 'ラバーリング・アクションゲーム', '新しくなったラバーリングアクション', '', 5800, '2019-04-25', 'https://swninfo.success-corp.co.jp/general/umihara-fresh/', 'https://www.youtube.com/embed/QYPgwcU-SSQ', 0, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (987, 'やわらかあたま塾 いっしょにあたまのストレッチ', 'ヤワラカアタマジュクイッショニアマタノストレッチ', '『やわらかあたま塾 いっしょにあたまのストレッチ』は、任天堂から2021年12月3日に発売されたNintendo Switch用のゲームソフトです（英題：Big Brain Academy: Brain vs. Brain）。\r\n\r\nこのゲームは、シリーズ最新作として14年ぶりに登場しました。ニンテンドーDS用のソフト『やわらかあたま塾』とWii用のソフト『Wiiでやわらかあたま塾』から選りすぐった問題を収録し、調整を加えています。', 'SW-047', 1, 7, 13, 'あたまのストレッチ', 'カタくなったあたまをもみほぐす', '', 2980, '2021-12-03', 'https://www.nintendo.co.jp/switch/azlsa/', 'https://www.youtube.com/embed/YaKojDXwWGw', 0, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (988, '東北大学加齢医学研究所 川島隆太教授監修 脳を鍛える大人のNintendo Switchトレーニング', 'トウホクダイガクミライカガクギジュキョウドウケンキュウセンターカワシマリュウタキョウジュカンシュウノウヲキタエルオトナノニンテンドースイッチトレーニング', '『脳を鍛える大人のNintendo Switchトレーニング』は、任天堂が開発・発売したNintendo Switch専用のゲームソフトです。\r\n\r\n正式なタイトルは『東北大学加齢医学研究所 川島隆太教授監修 脳を鍛える大人のNintendo Switchトレーニング』です。\r\n\r\nこの作品は、東北大学の川島隆太教授が監修し、『脳を鍛える大人のDSトレーニング』シリーズの第5作目としてリリースされました。前作である『ものすごく脳を鍛える5分間の鬼トレーニング』（通称：鬼トレ）からは7年ぶりの新作です。前作では主にワーキングメモリーのトレーニングがメインでしたが、今作では『ちょっと脳を鍛える大人のDSiトレーニング』以来の従来の脳トレが再びメインとなっています。\r\n\r\nパッケージ版には、専用のタッチペン（HAC-041）が同梱されています。\r\n\r\n収録されているトレーニングや脳年齢チェックのテストの多くは、過去のシリーズからの再収録となっていますが、一部の内容は変更されています。\r\n\r\n著作権クレジットは、『鬼トレ』と同様に、東北大学と任天堂の両方がクレジットされています。\r\n\r\nタッチペンを使用するため、実質的に携帯モードでのプレイ専用です。また、後述する『指計算』・『指体操』・『後出勝負テスト』の3つのトレーニングは、Joy-ConのモーションIRカメラを使って手をかざし、指を動かして行う形式になっています。なお、Nintendo Switch Liteではこの機能が搭載されていないため、これらの3つのトレーニングをプレイするには別途Joy-Conと充電器が必要です。', 'SW-043', 1, 7, 13, '脳活性化ソフト', '今の脳年齢を測ってみませんか？', '', 3480, '2019-12-27', 'https://www.nintendo.co.jp/switch/as3ma/index.html', 'https://www.youtube.com/embed/6_jnLSUquR8', 0, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (989, 'ベヨネッタ3', 'ベヨネッタスリー', '\r\n『ベヨネッタ3』は、プラチナゲームズが開発し、任天堂が2022年10月28日に発売したNintendo Switch用のアクションゲームです。シリーズの生みの親である神谷英樹はスーパーバイジングディレクターとして参加しています。\r\n\r\n舞台は別次元の地球、廃墟と化したニューヨーク。アンブラの魔女ベヨネッタは、謎の存在シンギュラリティが呼び出したホムンクルスなる生命体と交戦しています。しかし、魔獣には太刀打ちできず、シンギュラリティの力で拘束されてしまいます。そこに刀を持った謎の少女ヴィオラと彼女と共に行動するシグルズが現れ、ベヨネッタを助けようとしますが、ベヨネッタとシグルズは殺されてしまい、ヴィオラは謎の力でどこかへと転送されてしまいます。\r\n\r\n舞台は変わり、正史世界のニューヨークに移ります。ベヨネッタは情報屋のエンツォを扱き使い、豪華客船のパーティーに参加していますが、駐車場で待っていたエンツォの車の上にヴィオラが突然落ちてきてしまいます。彼女を追ってホムンクルス達も現れ、ニューヨークは大混乱に陥ってしまいます。ベヨネッタは世界を救うために再び立ち上がることになります。', 'SW-048', 1, 7, 1, '∞クライマックス・アクション', 'ノンストップ クライマックス・アクション', '', 6980, '2022-10-28', 'https://www.nintendo.co.jp/switch/axb7a/index.html', 'https://www.youtube.com/embed/OuXHM_zuc7k', 0, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (990, 'ベヨネッタ オリジンズ： セレッサと迷子の悪魔', 'ベヨネッタオリジンズセレッサトマイゴノアクマ', '編集中…', 'SW-049', 1, 7, 1, '', 'そして少女は、魔女になった', '', 5980, '2023-03-17', 'https://www.nintendo.co.jp/switch/axb8a/index.html', 'https://www.youtube.com/embed/mubOL8mPtDw', 0, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (991, 'ナビつき! つくってわかる はじめてゲームプログラミング', 'ナビツキツクッテワカルハジメテゲームプログラミング', '『ナビつき！つくってわかるはじめてゲームプログラミング』は、Nintendo Switch用のゲーム制作ソフトで、任天堂が2021年6月11日に発売したものです。このゲームは、Nintendo Labo Toy-Con 04: VR Kit内のToy-Con Garage VRを拡張したもので、通信機能などが追加されています。略称は『はじプロ』とされています。\r\n\r\nこのプログラミングソフトは、長いプログラムコードを書く必要がなく、コントローラーの各入力や動作などを司る「ノード」と呼ばれる部品を繋げることで、プログラムを構築することができます。例えば、「スティックノード」と「ヒトノードン」の『左右』を繋げることで、スティック操作によってゲーム内の人物を左右に動かすことができます。\r\n\r\nこのゲームは、プログラミングを学びたい初心者でも簡単に扱えるように設計されています。また、通信機能を利用して自分が制作したゲームを他の人と共有することもできます。', 'SW-050', 1, 7, 13, 'プログラミング', '直感的に理解出来るプログラミングゲーム', '', 3164, '2021-06-11', 'https://www.nintendo.co.jp/switch/awuxa/', 'https://www.youtube.com/embed/N9SvKfrmwUw', 1, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (992, 'Nintendo Switch Sports', 'ニンテンドースイッチスポーツ', '「Nintendo Switch Sports」は、任天堂が開発・販売したNintendo Switch専用のスポーツゲームソフトで、2022年4月29日に発売されました。本作は、「Wii Sports」シリーズの第4作目であり、2022年2月10日の「Nintendo Direct 2022.2.10」で発表されました。本作は、Wiiリモコンではなく、Joy-Conを使って遊ぶ、体感型のスポーツゲームとなっており、オンライン対戦も可能です。\r\n\r\n最初はテニス、ボウリング、チャンバラ、サッカー、バドミントン、バレーボールの6種目が収録されていましたが、11月29日のアップデートでゴルフが追加配信されました。プレイヤーはスポーツメイツというキャラクターと、自分のMiiキャラクターを使用してプレイすることができます。\r\n\r\nまた、サッカーではレッグバンドと呼ばれる特別なアクセサリーを使って、Joy-Conを腿に固定してプレイすることもできます。ただし、Nintendo Switch Liteでは本作をプレイすることができませんので、ご注意ください。', 'SW-051', 1, 7, 7, '', '家の中が競技場にスイッチ', '', 4980, '2022-04-29', 'https://www.nintendo.co.jp/switch/as8sa/', 'https://www.youtube.com/embed/ocgK-QLKCjk', 0, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (993, 'リングフィット アドベンチャー', 'リングフィット アドベンチャー', '『リングフィット アドベンチャー』は、任天堂から発売されたNintendo Switch専用のフィットネスゲームです。プレイヤーは、リングコンとレッグバンドを使ってプレイし、自分の動きが画面上の主人公と連動する形式で、アクションゲームやRPGのような冒険を進めていきます。リングコンにはJoy-Con（R）、レッグバンドにはJoy-Con（L）を装着し、リングコンとレッグバンドの位置や向きを認識するシステムになっています。携帯モードには対応していませんが、Nintendo Switch LiteでのプレイにはJoy-Con（L）/Joy-Con（R）が必要です。リングコンの内部には、繊維強化プラスチックが用いられており、力センサーやモーションIRカメラを搭載しています。本作では、「アドベンチャーモード」、「お手軽モード」、「カスタムモード」があり、リングコンの押し引き操作の判定強度を最大100まで設定することができます。プレイヤーは、ミブリさんというデモンストレーションキャラの案内を見ながら操作することができます。', 'SW-052', 1, 7, 7, 'フィットネス', '家庭で楽しみながらフィットネス', '', 7980, '2019-10-18', 'https://www.nintendo.co.jp/ring/', 'https://www.youtube.com/embed/qXfpVh7VI_c', 1, 0, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (994, 'Pokemon LEGENDS アルセウス', 'ポケモンレジェンズアルセウス', '『Pokémon LEGENDS アルセウス』は、2022年1月28日にNintendo Switch用アクションロールプレイングゲームとして発売されました。このゲームは、2021年2月27日に行われた『Pokémon Presents 2021.2.27』で、『ポケットモンスター ブリリアントダイヤモンド・シャイニングパール』と共に発表されました。\r\n\r\nこの作品は、「シンオウ地方」の前身である「ヒスイ地方」を描いた物語であり、『ポケットモンスター ダイヤモンド・パール』および、そのリメイクの『ポケットモンスター ブリリアントダイヤモンド・シャイニングパール』のスピンオフにあたります。また、ポケットモンスターオフィシャルサイトの中で、『ポケットモンスター』シリーズ（いわゆる本編シリーズ）の一つとして位置付けられています。\r\n\r\nこの作品は、シリーズ初のアクションRPGであり、ゲームシステムが多くの点で変更されています。また、シリーズで初めて日本語版タイトルに『Pokémon』のロゴを冠したタイトルとなっています。\r\n\r\n過去の作品では、毎回完全新作となるため、舞台及び最初のパートナー3匹が全く新規のものであったのに対し、『Pokémon LEGENDS アルセウス』は、舞台となる土地もパートナーも既存のもの（モクロー、初出：「サン・ムーン」・ヒノアラシ、初出：「金・銀」・ミジュマル、初出：「ブラック・ホワイト」）です。', 'SW-053', 19, 7, 3, 'アクションRPG', 'ポケモンの「過去の歴史」を紐解く', '', 5980, '2022-01-28', 'https://www.pokemon.co.jp/ex/legends_arceus/ja/', 'https://www.youtube.com/embed/7Uk0brE6jpU', 1, 0, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (995, 'ポケットモンスター Let’s Go! ピカチュウ', 'ポケットモンスターレッツゴーピカチュウ', '『ポケットモンスター Let''s Go! ピカチュウ・Let''s Go! イーブイ』は、2018年に株式会社ポケモンから発売されたNintendo Switch用のロールプレイングゲームです。このゲームは、1998年にゲームボーイ用ソフトとして発売された『ポケットモンスター ピカチュウ』をベースに、遊び方やシナリオをSwitch用に再構築した作品です。本作は、スマートフォン向けアプリ『Pokémon GO』で初めてポケモン作品に触れたユーザーが、次に遊ぶポケモン作品となることを想定しています。『Let''s Go! ピカチュウ』ではピカチュウが、『Let''s Go! イーブイ』ではイーブイが主人公の相棒となり、相棒のピカチュウおよびイーブイは衣装やアクセサリーの着せ替えと髪型の変更が可能です。本作は、『GO』との連携により『GO』で捕まえた一部のポケモンを本作に連れて行くことができます。略称は『ポケモン ピカ・ブイ』、『ピカブイ』です。', 'SW-054', 1, 7, 3, '', '大きく変わった捕獲の仕様', '', 5980, '2018-11-16', 'https://www.pokemon.co.jp/ex/pika_vee/', 'https://www.youtube.com/embed/JWhNT8cGTiM', 1, 1, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (996, 'ポケットモンスター Let’s Go! イーブイ', 'ポケットモンスターレッツゴーイーブイ', '『ポケットモンスター Let''s Go! ピカチュウ・Let''s Go! イーブイ』は、2018年に株式会社ポケモンから発売されたNintendo Switch用のロールプレイングゲームです。このゲームは、1998年にゲームボーイ用ソフトとして発売された『ポケットモンスター ピカチュウ』をベースに、遊び方やシナリオをSwitch用に再構築した作品です。本作は、スマートフォン向けアプリ『Pokémon GO』で初めてポケモン作品に触れたユーザーが、次に遊ぶポケモン作品となることを想定しています。『Let''s Go! ピカチュウ』ではピカチュウが、『Let''s Go! イーブイ』ではイーブイが主人公の相棒となり、相棒のピカチュウおよびイーブイは衣装やアクセサリーの着せ替えと髪型の変更が可能です。本作は、『GO』との連携により『GO』で捕まえた一部のポケモンを本作に連れて行くことができます。略称は『ポケモン ピカ・ブイ』、『ピカブイ』です。', 'SW-055', 1, 7, 3, '', '大きく変わった捕獲の仕様', '', 5980, '2018-11-16', 'https://www.pokemon.co.jp/ex/pika_vee/', 'https://www.youtube.com/embed/JWhNT8cGTiM', 1, 1, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (997, 'ポケットモンスター ソード', 'ポケットモンスターソード', '「ポケットモンスター ソード・シールド」とは、2019年11月15日に株式会社ポケモンより発売されたNintendo Switch用ロールプレイングゲームの総称で、ポケットモンスターシリーズの新作としては8作目にあたります。略称は「ポケモン剣盾」といいます。全世界で同時発売され、対応言語は日本語を含めた9言語です。本作の「ポケットモンスター」のロゴマークは、海外版のロゴマークと同様のフォントが使用されています。\r\n\r\nゲームは、ソード版とシールド版の2種類があります。また、2つを同梱したダブルパックも発売されており、特別なマックスレイドバトルへ序盤からアクセスできるゲーム内アイテムを入手できます。早期購入特典として、ゲーム内でキョダイマックスできる特別なニャースが配信されました。さらに、パッケージ版は購入する店舗によって様々なファングッズが、デジタル版はゲーム内で使えるアイテムがそれぞれ配布されました。また、過去に発売された「Let''s Go! ピカチュウ・イーブイ」を所持しているユーザーには、キョダイマックスできる特別なピカチュウもしくはイーブイが配信されました。\r\n\r\nさらに、有料ダウンロードコンテンツとして、「鎧の孤島」「冠の雪原」という2つの追加シナリオが配信されました。これらのコンテンツを購入することで、新しいストーリーやポケモン、アイテムなどが追加されます。', 'SW-056', 1, 7, 3, 'https://a.r10.to/huN5ao', 'ポケモンが巨大化する「ダイマックス」', '', 5980, '2019-11-15', 'https://www.pokemon.co.jp/ex/sword_shield/', 'https://www.youtube.com/embed/UHJB5OFpEDM', 1, 1, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (998, 'ポケットモンスター シールド', 'ポケットモンスターシールド', '「ポケットモンスター ソード・シールド」とは、2019年11月15日に株式会社ポケモンより発売されたNintendo Switch用ロールプレイングゲームの総称で、ポケットモンスターシリーズの新作としては8作目にあたります。略称は「ポケモン剣盾」といいます。全世界で同時発売され、対応言語は日本語を含めた9言語です。本作の「ポケットモンスター」のロゴマークは、海外版のロゴマークと同様のフォントが使用されています。\r\n\r\nゲームは、ソード版とシールド版の2種類があります。また、2つを同梱したダブルパックも発売されており、特別なマックスレイドバトルへ序盤からアクセスできるゲーム内アイテムを入手できます。早期購入特典として、ゲーム内でキョダイマックスできる特別なニャースが配信されました。さらに、パッケージ版は購入する店舗によって様々なファングッズが、デジタル版はゲーム内で使えるアイテムがそれぞれ配布されました。また、過去に発売された「Let''s Go! ピカチュウ・イーブイ」を所持しているユーザーには、キョダイマックスできる特別なピカチュウもしくはイーブイが配信されました。\r\n\r\nさらに、有料ダウンロードコンテンツとして、「鎧の孤島」「冠の雪原」という2つの追加シナリオが配信されました。これらのコンテンツを購入することで、新しいストーリーやポケモン、アイテムなどが追加されます。', 'SW-057', 1, 7, 3, '', 'ポケモンが巨大化する「ダイマックス」', '', 5980, '2019-11-15', 'https://www.pokemon.co.jp/ex/sword_shield/', '', 1, 1, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (999, 'ポケットモンスター ブリリアントダイヤモンド', 'ポケットモンスターブリリアントダイヤモンド', '『ポケットモンスター ブリリアントダイヤモンド・シャイニングパール』は、Nintendo Switchで遊ぶことができるロールプレイングゲームで、2021年11月19日に発売されました。このゲームは、『ポケットモンスター ダイヤモンド・パール』という、かつてニンテンドーDSで発売されたゲームをリメイクしたものであり、略称は「BDSP」「ダイパリメイク」と呼ばれています。\r\n\r\nストーリーは、オリジナル版を忠実に再現し、フィールドのグラフィックも当時のドット絵をそのまま3DCGに起こしたような見た目になっています。また、ポケットモンスターの本編シリーズの開発は、これまでゲームフリークとクリーチャーズが担当してきましたが、今回はILCAという会社が初めて参加しています。\r\n\r\n『ポケットモンスター ブリリアントダイヤモンド』と『ポケットモンスター シャイニングパール』は、ポケットモンスターの完全新作の4作目であり、Nintendo Switch用にアレンジされたリメイク作品となっています。これらのゲームは、ポケットモンスターのファンにはたまらない体験ができることでしょう。', 'SW-058', 1, 7, 3, '', 'あの輝きを、再び―', '', 5980, '2021-11-19', 'https://www.pokemon.co.jp/ex/bdsp/ja/', 'https://www.youtube.com/embed/CFSIV5Zvgyg', 1, 1, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (1000, 'ポケットモンスター シャイニングパール', 'ポケットモンスターシャイニングパール', '『ポケットモンスター ブリリアントダイヤモンド・シャイニングパール』は、Nintendo Switchで遊ぶことができるロールプレイングゲームで、2021年11月19日に発売されました。このゲームは、『ポケットモンスター ダイヤモンド・パール』という、かつてニンテンドーDSで発売されたゲームをリメイクしたものであり、略称は「BDSP」「ダイパリメイク」と呼ばれています。\r\n\r\nストーリーは、オリジナル版を忠実に再現し、フィールドのグラフィックも当時のドット絵をそのまま3DCGに起こしたような見た目になっています。また、ポケットモンスターの本編シリーズの開発は、これまでゲームフリークとクリーチャーズが担当してきましたが、今回はILCAという会社が初めて参加しています。\r\n\r\n『ポケットモンスター ブリリアントダイヤモンド』と『ポケットモンスター シャイニングパール』は、ポケットモンスターの完全新作の4作目であり、Nintendo Switch用にアレンジされたリメイク作品となっています。これらのゲームは、ポケットモンスターのファンにはたまらない体験ができることでしょう。', 'SW-059', 1, 7, 3, '', 'あの輝きを、再び―', '', 5980, '2021-11-19', 'https://www.pokemon.co.jp/ex/bdsp/ja/', 'https://www.youtube.com/embed/CFSIV5Zvgyg', 0, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (1001, 'ポケットモンスター スカーレット', 'ポケットモンスタースカーレット', '『ポケットモンスター スカーレット・バイオレット』とは、2022年11月18日に株式会社ポケモンより発売されるNintendo Switch用ロールプレイングゲームの総称で、ポケットモンスターシリーズの完全新作の9作目にあたります。略称は「ポケモンSV」です。\r\n\r\n本作は、オープンワールドを採用しており、プレイヤーは自由に駆け巡ることができます。また、従来のポケモンシリーズにおけるジムバトルとチャンピオンリーグも存在し、どのジムからでも自由に挑戦が可能となっていますが、トレーナーのポケモンレベルに関しては固定されています。このため、ある程度道筋は決まっていると言えます。\r\n\r\nまた、本作では過去作にあった戦闘アニメのカットが廃止され、よりスムーズなプレイが可能となっています。\r\n\r\n『ポケットモンスター スカーレット・バイオレット』は、2022年2月27日に『Pokémon Presents 2022.2.27』で発表され、同年の6月1日には「2nd Trailer」が公開され、公式サイトも更新されました。さらに、2023年春には『Pokémon HOME』と連携することでこれまでのシリーズに登場したポケモン（『LEGENDS アルセウス』に登場するポケモンも含め）を連れてくることが可能になる予定です。\r\n\r\n『ポケットモンスター スカーレット・バイオレット』は、日本語、英語、スペイン語（欧州スペイン語）、フランス語、ドイツ語、イタリア語、朝鮮語、中国語（繁体字、簡体字）の9言語に対応しています。', 'SW-060', 1, 7, 3, '', 'シリーズ初のオープンワールド', '', 5980, '2022-11-18', 'https://www.pokemon.co.jp/ex/sv/ja/', 'https://www.youtube.com/embed/or84Nt7nTmo', 1, 1, 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (1002, 'ポケットモンスター バイオレット', 'ポケットモンスターバイオレット', '『ポケットモンスター スカーレット・バイオレット』とは、2022年11月18日に株式会社ポケモンより発売されるNintendo Switch用ロールプレイングゲームの総称で、ポケットモンスターシリーズの完全新作の9作目にあたります。略称は「ポケモンSV」です。\r\n\r\n本作は、オープンワールドを採用しており、プレイヤーは自由に駆け巡ることができます。また、従来のポケモンシリーズにおけるジムバトルとチャンピオンリーグも存在し、どのジムからでも自由に挑戦が可能となっていますが、トレーナーのポケモンレベルに関しては固定されています。このため、ある程度道筋は決まっていると言えます。\r\n\r\nまた、本作では過去作にあった戦闘アニメのカットが廃止され、よりスムーズなプレイが可能となっています。\r\n\r\n『ポケットモンスター スカーレット・バイオレット』は、2022年2月27日に『Pokémon Presents 2022.2.27』で発表され、同年の6月1日には「2nd Trailer」が公開され、公式サイトも更新されました。さらに、2023年春には『Pokémon HOME』と連携することでこれまでのシリーズに登場したポケモン（『LEGENDS アルセウス』に登場するポケモンも含め）を連れてくることが可能になる予定です。\r\n\r\n『ポケットモンスター スカーレット・バイオレット』は、日本語、英語、スペイン語（欧州スペイン語）、フランス語、ドイツ語、イタリア語、朝鮮語、中国語（繁体字、簡体字）の9言語に対応しています。', 'SW-061', 1, 7, 3, '', 'シリーズ初のオープンワールド', '', 5980, '2022-11-18', 'https://www.pokemon.co.jp/ex/sv/ja/', 'https://www.youtube.com/embed/or84Nt7nTmo', 1, 1, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (1003, 'ポケモン不思議のダンジョン 救助隊DX', 'ポケモンフシギノダンジョンキュウジョタイデラックス', '『ポケモン不思議のダンジョン 救助隊DX』は、2020年3月6日にポケモンからNintendo Switchで発売されたゲームです。このゲームは、ニンテンドーDSの『青の救助隊』とゲームボーイアドバンスの『赤の救助隊』を1つのソフトにしたリメイク作品で、絵本のようなビジュアルで描かれています。1月10日には、無料の体験版が配信され、物語の序盤を遊ぶことができ、製品版に引き継ぐことができます。\r\n\r\n開発者は、2005年当時のチュンソフトであり、現社名はスパイク・チュンソフトとなっています。このリメイク版では、『ポケットモンスター ダイヤモンド・パール』以降に登場したポケモンは基本的に登場せず、石像でしか登場しなかったポケモンであるルカリオや、マニューラやウソハチといった『ポケットモンスター ルビー・サファイア』までのポケモンの追加進化と進化前、およびフシギバナやリザードン、ゲンガーなどのメガシンカポケモンも登場します。\r\n\r\nこのゲームには、ダンジョン内で倒れてしまった時に、インターネットに接続されている他のプレイヤーに救助してもらえる機能がありますが、Nintendo Switch Onlineに加入していないプレイヤーは使用できないことに注意してください。', 'SW-062', 1, 7, 3, 'ダンジョンRPG', 'ある日突然ポケモンになっちゃった！', '', 5980, '2020-03-06', 'https://www.pokemon.co.jp/ex/dungeonDX/', 'https://www.youtube.com/embed/mw5pmakFtVg', 1, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (1004, 'New ポケモンスナップ', 'ニューポケモンスナップ', '『New ポケモンスナップ』は、2021年4月30日に株式会社ポケモンから発売されたNintendo Switch用ゲームソフトで、バンダイナムコスタジオ（BNSI）が開発しました。このゲームは、1999年に発売されたNINTENDO64用ソフト『ポケモンスナップ』のシステムをベースにした完全新作で、続編にあたります。BNSIが手掛ける『ポケットモンスター』のスピンオフゲームは、親会社バンダイナムコエンターテインメント（BNEI）制作の『ポッ拳 POKKÉN TOURNAMENT』以来2作目かつ初の単独開発です。\r\n\r\nゲームの舞台は未開の地「レンティル地方」で、ポケモンの生態やこの地方独自の現象「イルミナ現象」の調査を進めていきます。プレイヤーはポッド型の乗り物「ネオワン号」に乗り込み、レンティル地方を探検しながら、ポケモンの写真を撮影していきます。このゲームには、『ソード・シールド』までに登場した200匹以上のポケモンが登場し、各ポケモンの鳴き声はピカチュウ以外は実在の動物のような鳴き声を発しています。\r\n\r\n『New ポケモンスナップ』は、2020年6月17日に配信された新作発表会「Pokémon Presents」において、開発中であることが発表され、2021年1月14日に発売日が発表されました。', 'SW-063', 19, 7, 1, 'カメラアクション', 'キミも今日からポケモンカメラマン', '', 5980, '2021-04-30', 'https://www.pokemon.co.jp/ex/newpokemonsnap/', 'https://www.youtube.com/embed/ZYm_shrEyX8', 1, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `games` (`id`, `name`, `kana`, `overview`, `code`, `manufacturer_id`, `machine_id`, `genre_id`, `sub_genre`, `catch_copy`, `sub_catch`, `list_price`, `release_date`, `official_site_url`, `youtube_url`, `is_play`, `is_clear`, `is_favourite`, `created_at`, `updated_at`) VALUES (1005, 'ゼルダの伝説 ティアーズ オブ ザ キングダム', 'ゼルダノデンセツティアーズ オブ ザ キングダム', '『ゼルダの伝説 ティアーズ オブ ザ キングダム』は、2023年5月12日に任天堂から発売されたオープンワールドアクションアドベンチャーゲームです。このゲームのキャッチコピーは「翔ける、創る、紡ぐ。果てなき冒険は、大空へ広がる。」です。\r\n\r\n『ゼルダの伝説 ティアーズ オブ ザ キングダム』は、2017年に発売されたゲーム『ゼルダの伝説 ブレス オブ ザ ワイルド』の続編です。\r\n\r\nこのゲームは、2019年6月12日に放送された『Nintendo Direct E3 2019』で開発が発表されました。その後、2022年内の発売が予定されていましたが、2022年3月29日に発売が2023年春に変更されると発表されました。\r\n\r\n2023年2月9日の「Nintendo Direct 2023.2.9」で、ゲームの2ndトレーラーが発表され、予約が開始されました。さらに、コレクターズエディション版や新しい主人公リンクのamiiboなども発表されました。\r\n\r\nしかし、2023年2月19日には、コレクターズエディション版のアートブックの画像がRedditに大量にリークされる事件が発生しました。任天堂はリーク者の個人情報開示を求めるDMCA通知を発信しました。\r\n\r\n2023年3月28日には、プロデューサーである青沼英二によるプレイ映像が公開されました。この映像では、前作と同じくハイラルの大地に加えて、「空島」と呼ばれる空中の地域や新しい敵NPC、改良されたゲームシステムなどが紹介されました。\r\n\r\n同年4月13日には、最後の告知PVとなる3rdトレーラーが公開されました。このPVでは、多くのカットシーンやプレイ映像が披露され、新しいキャラクターや集団戦、新ガジェットによるプレイなどが紹介されました。\r\n\r\nタイトルの「Tears of the Kingdom」は、「王国の涙」と訳されます。最初の発表時には、この表記の意味が明確ではありませんでしたが、任天堂は外国のメディアからの問い合わせに対し、「Tear」は泣くことを意味すると回答', 'SW-107', 1, 7, 1, 'アクションアドベンチャーゲーム', '翔ける、創る、紡ぐ。果てなき冒険は、大空へ広がる。', '', 7200, '2023-05-12', 'https://www.nintendo.co.jp/zelda/totk/index.html', 'https://www.youtube.com/embed/-MEo1tGalr0', 1, 0, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
